INSERT INTO `object_filters`(`deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `id`, `label`, `source`, `formula`, `is_desc`, `object_id`, `sort_field`, `dependency_field_id`, `name`, `display`, `search_fields`, `next_dependency_fields`, `external_condition`, `ignore_rls`, `include_deleted_record`, `external_condition_args`) VALUES ('0', '1', '2018-07-24 03:14:36', '1', '2019-11-22 05:57:34', '46f4d95c-2ddb-4777-825d-1afb35046d4a', '目标医生', 'system', NULL, '0', '6ed2cbde-90f3-asfz-96b0-e4b318c6b596', 'f81c8df7-88d5-4f3c-a153-fb5055ffd8a2', NULL, 'product_metrics', 'standard', NULL, NULL, '
from django.db import models as djm 
from orionbase.common import models 
from orion.common.user import get_current_user_id 
from orion.sales_unit.sales_unit import get_related_product_metrics 
from orionbase.common import orion_function
from orion.sales_target_management import ps
from orionbase.utils.utils import DateUtils

def get_condition(filter, dependency, **kwargs):     
    position_history_id = kwargs[\'position_history_id\']
    hospital_packages = kwargs[\'hospital_packages\']
    professional_name = kwargs[\'professional_name\']
    product_metrics = orion_function.get_position_related_product_metrics(position_history_id, hospital_packages)
    if product_metrics:
            if professional_name:
                return djm.Q(pk__in=product_metrics, professional__name__icontains=professional_name)
            else:
                return djm.Q(pk__in=product_metrics) 
    else:
        return djm.Q(pk=None) ', NULL, NULL, NULL) ;
