from django.db import models as djm
from orionbase.common import models
from orionbase.utils.utils import DateUtils

from orion.position.position import get_sub_positions
from orion.common.user import get_current_user_id
def get_condition(filter, dependency, version=None):
    if not version:
        version = DateUtils.get_current_datetime_as_str(\'%Y-%m\')
    return djm.Q(version__name=version)
